import React, { useState } from "react";
import "./Login.css";   // ✅ YOUR UI BACK

function Login() {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");

  const handleLogin = async (e) => {
    e.preventDefault();

    try {
      const res = await fetch("https://prasa-app-yde3.onrender.com/api/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ empld, password }),
      });

      const data = await res.json();
      console.log("LOGIN RESPONSE:", data);

      if (!data.success) {
        alert(data.message || "Invalid login");
      } else {
        alert("Login successful");
      }
    } catch (err) {
      console.error("Login Error:", err);
      alert("Server error");
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        
        {/* Logo */}
        <div className="logo-container">
          <img
            className="login-logo"
            src="/assets/prasa-logo.png"
            alt="PRASA"
          />
        </div>

        <h2 className="login-title">PRASA Employee Portal</h2>

        <form onSubmit={handleLogin}>
          <label>EMP ID</label>
          <input
            type="text"
            className="input-box"
            placeholder="EMP001"
            value={empld}
            onChange={(e) => setEmpld(e.target.value)}
          />

          <label>Password</label>
          <input
            type="password"
            className="input-box"
            placeholder="Enter Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <button type="submit" className="btn-login">
            Login
          </button>

        </form>
      </div>
    </div>
  );
}

export default Login;
